            <div id="show-admin-main-menu" class="show-admin-main-menu">
                <svg id="show-admin-main-burger" width="24" height="24" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M23.063 11.063H.938a.937.937 0 1 0 0 1.874h22.125a.937.937 0 1 0 0-1.874ZM23.063 3.563H.938a.937.937 0 1 0 0 1.874h22.125a.937.937 0 1 0 0-1.875ZM23.063 18.563H.938a.937.937 0 1 0 0 1.875h22.125a.937.937 0 1 0 0-1.875Z" fill="#353535"/></svg>
            
                <div id="main-menu-container" class="main-menu-container">
                    <nav id="user-left-menu" class="user-left-menu">@include('front/left-menu')</nav>
                </div>
            </div>    
            
        </div>
    </nav>

    <div class="front-content-container">
        @yield('content')
    </div>
    
    <div class="bg-light mt-5 border-top">
        <div class="container">
            @include('auth/footer')
        </div>
    </div>
       
<script>
    document.getElementById('show-admin-main-menu').addEventListener("click", function(){
        let menuContainer = document.getElementById('main-menu-container');
        if (menuContainer.classList.contains('main-menu-opened')){
            menuContainer.classList.remove('main-menu-opened');
        } else {
            menuContainer.classList.add('main-menu-opened');
        }
    });
</script>     
